import{_ as d,o as i,c as t,a3 as a}from"./chunks/framework.LBeL10WQ.js";const p=JSON.parse('{"title":"Glossaire","description":"","frontmatter":{"title":"Glossaire"},"headers":[],"relativePath":"glossary.md","filePath":"glossary.md"}'),r={name:"glossary.md"};function n(s,e,o,l,u,c){return i(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="glossaire-du-retail-media" tabindex="-1">Glossaire du Retail Media <a class="header-anchor" href="#glossaire-du-retail-media" aria-label="Permalink to &quot;Glossaire du Retail Media&quot;">​</a></h1><p>Définitions des termes techniques et acronymes de la plateforme.</p><div class="gi-alpha-nav"><a href="#a">A</a><a href="#b">B</a><a href="#c">C</a><a href="#d">D</a><a href="#e">E</a><a href="#f">F</a><a href="#l">L</a><a href="#o">O</a><a href="#p">P</a><a href="#q">Q</a><a href="#r">R</a><a href="#t">T</a><a href="#u">U</a><a href="#z">Z</a></div><h2 id="a">A</h2><dl><dt>Annonceur (Advertiser)</dt><dd>Marque qui achète de l&#39;espace publicitaire pour promouvoir ses produits ou services.</dd><dt>Insertion Colis (Sponsored Mail)</dt><dd>Technique marketing consistant à insérer une offre publicitaire (flyer, carte, échantillon) à l&#39;intérieur du colis d&#39;expédition d&#39;un e-commerçant partenaire.</dd><dt>Audience Lookalike</dt><dd>Ciblage publicitaire visant des profils ayant des caractéristiques similaires (comportement d&#39;achat, démographie) à une base de clients existante.</dd></dl><hr><h2 id="b">B</h2><dl><dt>BAT (Bon à Tirer)</dt><dd>Validation finale de la maquette (numérique) avant le lancement de la production. Une fois validé, aucune modification n&#39;est possible.</dd><dt>Brief</dt><dd>Document rempli par l&#39;Annonceur détaillant ses objectifs et fournissant les éléments graphiques nécessaires à la campagne.</dd></dl><hr><h2 id="c">C</h2><dl><dt>Capping</dt><dd>Limite de volume imposée à une campagne (ex: limiter à 1 flyer par colis maximum).</dd><dt>Co-branding</dt><dd>Association de deux marques (l&#39;Annonceur et le Distributeur) dans une même communication pour renforcer l&#39;impact.</dd><dt>CPA (Coût Par Acquisition)</dt><dd>Coût moyen dépensé pour générer une vente ou un lead.</dd><dt>CPM (Coût Pour Mille)</dt><dd>Unité de mesure standard. Un CPM de 15€ signifie que l&#39;annonceur paie 15€ pour 1 000 impressions.</dd></dl><hr><h2 id="d">D</h2><dl><dt>Distributeur (Publisher/Retailer)</dt><dd>E-commerçant ou Média qui monétise son audience en diffusant les publicités d&#39;annonceurs tiers.</dd><dt>DNVB</dt><dd>Digital Native Vertical Brand. Marque née sur internet vendant en direct.</dd></dl><hr><h2 id="e">E</h2><dl><dt>Echantillonnage (Sampling)</dt><dd>Distribution gratuite d&#39;un produit en format réduit pour le faire tester.</dd><dt>Endorsement</dt><dd>Caution apportée par le Distributeur à l&#39;Annonceur. Le fait que l&#39;e-commerçant &quot;parle&quot; de la marque renforce la confiance.</dd></dl><hr><h2 id="f">F</h2><dl><dt>FOGRA39</dt><dd>Profil colorimétrique standard pour l&#39;impression offset en Europe.</dd><dt>Fond Perdu (Bleed)</dt><dd>Zone imprimée dépassant le format final (2-3 mm) pour éviter les liserés blancs à la découpe.</dd></dl><hr><h2 id="l">L</h2><dl><dt>Landing Page</dt><dd>Page web spécifique vers laquelle l&#39;utilisateur est redirigé après avoir cliqué sur une offre.</dd><dt>Lead Time (Délai d&#39;ingestion)</dt><dd>Délai logistique incompressible entre la réception des flyers et leur insertion effective dans les premiers colis.</dd></dl><hr><h2 id="o">O</h2><dl><dt>Opt-in</dt><dd>Consentement explicite de l&#39;internaute à recevoir des communications commerciales.</dd></dl><hr><h2 id="p">P</h2><dl><dt>Pixel de Tracking</dt><dd>Petit morceau de code (image 1x1) inséré dans un email pour comptabiliser les ouvertures.</dd></dl><hr><h2 id="q">Q</h2><dl><dt>QR Code Dynamique</dt><dd>Code 2D dont l&#39;URL de destination peut être modifiée à distance après l&#39;impression.</dd></dl><hr><h2 id="r">R</h2><dl><dt>Retail Media</dt><dd>Dispositifs publicitaires présents sur les parcours d&#39;achat des e-commerçants (Colis, Web, Email).</dd><dt>ROI</dt><dd>Retour sur Investissement.</dd></dl><hr><h2 id="t">T</h2><dl><dt>Taux d&#39;ouverture (Open Rate)</dt><dd>Pourcentage de destinataires ayant ouvert l&#39;email.</dd><dt>Triman (Info-tri)</dt><dd>Logo obligatoire en France indiquant comment trier le déchet.</dd></dl><hr><h2 id="u">U</h2><dl><dt>UTM</dt><dd>Paramètres ajoutés à la fin d&#39;une URL (ex: `?utm_source=getinside`) pour tracker la source du trafic.</dd></dl><hr><h2 id="z">Z</h2><dl><dt>Zone Tranquille</dt><dd>Marge de sécurité intérieure où il ne faut placer aucun texte important.</dd></dl>',44)])])}const h=d(r,[["render",n]]);export{p as __pageData,h as default};
